*event_6
;[exp] inSearching || onObjectTrigger


@question title="There is a stone monument. Would you like to touch it?"
[eventoff cond='! tf.result']
@wait time=500
@playse storage=tremble
@quake time=3000 hmax=5 vmax=0
@wq
@playse storage=rockdrop
@changewall x=4 y=7 way=n himg=arch type=space behind=true
@changewall x=5 y=7 way=n himg=arch type=space behind=true
@changewall x=4 y=6 way=s himg=arch type=space behind=true
@changewall x=5 y=6 way=s himg=arch type=space behind=true
@changewall x=4 y=7 way=w himg=arch type=space behind=true
@changewall x=4 y=6 way=w himg=arch type=space behind=true
@changewall x=5 y=7 way=e himg=arch type=space behind=true
@changewall x=5 y=6 way=e himg=arch type=space behind=true
@wait time=800
@notice text="I heard the sound of something heavy moving somewhere!"
@delevent

